import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestionsBatch34: CareerQuestion[] = [
  { id: "pta-b34-001", stem: "A PTA is performing cardiac rehabilitation with a 62-year-old patient who recently underwent coronary artery bypass graft (CABG) surgery. During phase I inpatient rehab, the patient's heart rate increases from 72 bpm at rest to 118 bpm during ambulation with a corresponding blood pressure drop from 130/82 to 98/60 mmHg. The PTA should:", options: ["Continue ambulation as these are expected post-surgical responses", "Stop the activity immediately, return the patient to a seated or supine position, monitor vital signs, and notify the supervising PT and nursing staff", "Increase the walking speed to improve cardiovascular conditioning", "Administer sublingual nitroglycerin independently"], correctIndex: 1, rationale: "A heart rate increase greater than 20-30 bpm above resting combined with a systolic blood pressure drop of more than 20 mmHg during activity indicates exercise intolerance and potential hemodynamic instability. These responses exceed safe parameters for phase I cardiac rehab (typically HR should stay below 120 bpm or 20 bpm above resting, and SBP should not drop). Continuing or increasing activity risks cardiovascular collapse. The PTA cannot independently administer medications. Stopping activity and notifying the team is the appropriate response.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "Post-CABG Exercise Intolerance" },
  { id: "pta-b34-002", stem: "A PTA is treating a patient with a stage 3 pressure injury over the sacrum. The wound bed is 70% granulation tissue and 30% yellow slough. The surrounding periwound skin is macerated. Which dressing approach is MOST appropriate?", options: ["Applying a moisture-retentive hydrogel to the entire wound and periwound area", "Using a foam dressing with a moisture barrier applied to the periwound skin to manage excess exudate while protecting macerated tissue", "Packing the wound tightly with dry gauze and taping over it", "Leaving the wound open to air to dry out the macerated periwound skin"], correctIndex: 1, rationale: "Periwound maceration indicates excessive moisture that is damaging intact skin. A foam dressing absorbs excess exudate while maintaining a moist wound bed for the granulation tissue. Applying a moisture barrier (skin protectant) to the periwound addresses maceration. Hydrogel adds moisture, which would worsen maceration. Dry gauze desiccates the wound bed and damages granulation tissue. Leaving the wound open to air does not maintain the moist wound healing environment needed for granulation and risks contamination.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Periwound Maceration Management" },
  { id: "pta-b34-003", stem: "A PTA is evaluating a patient with a transfemoral (above-knee) amputation who is being fitted for a prosthesis. The patient demonstrates a lateral trunk lean toward the prosthetic side during stance phase. This gait deviation is MOST likely caused by:", options: ["The prosthetic limb is too short, causing the patient to lean toward that side to maintain contact with the ground", "The prosthetic limb is too long", "Excessive prosthetic knee flexion during stance", "Insufficient socket fit causing distal discomfort"], correctIndex: 0, rationale: "Lateral trunk lean toward the prosthetic side during stance is a classic compensation for a prosthesis that is too short. The patient shifts their center of mass laterally to shorten the sound side and maintain ground contact on the prosthetic side. A prosthesis that is too long would cause contralateral trunk lean or vaulting on the sound side. Excessive knee flexion would cause instability, not lateral lean. While an insufficient socket fit can cause various deviations, the specific pattern of ipsilateral lateral lean most directly correlates with inadequate prosthetic length.", difficulty: 2, category: "Prosthetics & Orthotics", topic: "Transfemoral Lateral Trunk Lean" },
  { id: "pta-b34-004", stem: "A PTA is treating a patient who takes carvedilol (a beta-blocker) for heart failure. During exercise, the PTA notices the patient's heart rate remains at 78 bpm despite vigorous activity. The PTA should understand that:", options: ["The patient is not exercising hard enough and should increase intensity until heart rate rises appropriately", "Beta-blockers blunt the heart rate response to exercise, making heart rate an unreliable indicator of exercise intensity; the Rating of Perceived Exertion (RPE) scale should be used instead", "Carvedilol has no effect on exercise heart rate", "A constant heart rate during exercise indicates excellent cardiovascular fitness"], correctIndex: 1, rationale: "Beta-blockers (carvedilol, metoprolol, atenolol) block beta-1 adrenergic receptors in the heart, attenuating the chronotropic response to exercise. This means heart rate will not increase proportionally to exercise intensity, making traditional heart rate-based exercise prescription unreliable. The RPE scale (Borg 6-20 or 0-10) provides a subjective but effective alternative for monitoring intensity. Pushing for higher heart rates could be dangerous. Beta-blockers specifically blunt heart rate response. A blunted heart rate during vigorous exercise in a heart failure patient on beta-blockers is pharmacological, not a sign of fitness.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Beta-Blocker Exercise Heart Rate" },
  { id: "pta-b34-005", stem: "A PTA is analyzing a patient's gait and observes that during the loading response phase of gait, the ground reaction force vector passes anterior to the knee joint center. This biomechanical finding indicates:", options: ["An external knee flexion moment requiring quadriceps activation to prevent knee buckling", "An external knee extension moment requiring hamstring activation", "Normal knee biomechanics during loading response where the ground reaction force creates a stabilizing knee extension moment", "A pathological gait pattern requiring immediate cessation of ambulation"], correctIndex: 2, rationale: "During normal loading response, the ground reaction force (GRF) vector typically passes anterior to the knee joint center, creating an external knee extension moment. This is a stabilizing force that helps prevent knee collapse without excessive quadriceps demand. If the GRF vector passed posterior to the knee, it would create an external flexion moment requiring strong quadriceps contraction to prevent buckling. The anterior GRF position during loading response is a normal biomechanical feature of efficient gait, not pathological. Understanding GRF vector relationships to joint centers is fundamental to gait analysis.", difficulty: 3, category: "Biomechanics & Kinesiology", topic: "Ground Reaction Force Knee Moment" },
  { id: "pta-b34-006", stem: "A PTA is reviewing a randomized controlled trial (RCT) that examined the effectiveness of dry needling for chronic low back pain. The study reports a p-value of 0.03 and a 95% confidence interval for the mean difference in pain scores of -0.8 to -0.1 (on a 10-point scale). The minimal clinically important difference (MCID) for this pain scale is 2.0 points. The PTA should interpret these results as:", options: ["Both statistically and clinically significant, supporting the use of dry needling", "Statistically significant but NOT clinically significant, as the entire confidence interval falls below the MCID of 2.0 points", "Neither statistically nor clinically significant", "Clinically significant but not statistically significant"], correctIndex: 1, rationale: "The p-value of 0.03 is below the conventional 0.05 threshold, indicating statistical significance. However, the 95% confidence interval (-0.8 to -0.1) shows the true treatment effect likely falls between a 0.1 and 0.8 point improvement, which is entirely below the MCID of 2.0 points. This means the improvement, while unlikely due to chance, is too small to be meaningful to patients. Statistical significance does not guarantee clinical relevance. Evidence-based practice requires evaluating both statistical and clinical significance when interpreting research findings.", difficulty: 3, category: "Evidence-Based Practice", topic: "Statistical vs Clinical Significance" },
  { id: "pta-b34-007", stem: "A PTA is treating a patient with complex regional pain syndrome (CRPS) Type I affecting the right hand. The patient reports burning pain rated 8/10, with visible edema, skin color changes (mottled purple), and temperature asymmetry compared to the left hand. The MOST appropriate initial treatment approach is:", options: ["Aggressive passive range of motion to prevent joint contracture", "Graded motor imagery (GMI) progressing from laterality recognition to imagined movements to mirror therapy, combined with edema management and desensitization", "Complete immobilization of the right hand in a resting splint for 6 weeks", "Deep tissue massage directly over the affected hand"], correctIndex: 1, rationale: "Graded motor imagery is an evidence-based approach for CRPS that addresses central sensitization through a progressive sequence: laterality recognition (identifying left vs. right hand images), imagined movements (mental rehearsal without actual movement), and mirror therapy (using the unaffected hand's reflection to create pain-free movement illusion). This approach reduces cortical reorganization associated with CRPS. Aggressive PROM can exacerbate CRPS pain and inflammation. Complete immobilization promotes disuse and worsens CRPS. Deep tissue massage over a sensitized area would dramatically increase pain and potentially worsen the condition.", difficulty: 3, category: "Pain Management", topic: "CRPS Graded Motor Imagery" },
  { id: "pta-b34-008", stem: "A PTA is working in an outpatient clinic with a full schedule of 12 patients. A new patient arrives for evaluation but the supervising PT is detained in a meeting. Two existing patients need treatment for their scheduled sessions, and a third patient reports new onset of chest pain. The PTA should FIRST:", options: ["Begin treating the two scheduled patients while waiting for the PT", "Attend to the patient with new onset chest pain by activating emergency protocols, calling for help, and monitoring the patient", "Begin the new patient evaluation independently to stay on schedule", "Send all patients home and close the clinic until the PT returns"], correctIndex: 1, rationale: "Patient safety always takes priority in clinical decision-making. New onset chest pain is a potential medical emergency requiring immediate attention. The PTA should activate emergency protocols (call 911 if indicated), stay with the patient, monitor vital signs, and call for help. The PTA cannot perform initial evaluations (PT scope only). Treating scheduled patients while ignoring a potential cardiac event is negligent. Closing the clinic entirely is an overreaction that delays care for the emergency patient. Clinical prioritization demands addressing life-threatening situations first regardless of scheduling pressures.", difficulty: 1, category: "Clinical Prioritization & Workflow", topic: "Emergency Triage in Outpatient" },
  { id: "pta-b34-009", stem: "A PTA is performing chest physiotherapy including postural drainage for a patient with bronchiectasis affecting the posterior basal segments of both lower lobes. The correct patient position for draining these segments is:", options: ["Sitting upright in a chair", "Prone with the foot of the bed elevated 18-20 inches (Trendelenburg position)", "Supine with the head of bed elevated 30 degrees", "Side-lying on the affected side with no bed elevation"], correctIndex: 1, rationale: "The posterior basal segments of the lower lobes are the most gravity-dependent portions of the lung when upright. To drain these segments, the patient is positioned prone (to orient the posterior segments superiorly relative to the bronchi) with the foot of the bed elevated 18-20 inches (Trendelenburg) to use gravity to move secretions from the lower lobes toward the main bronchi. Sitting upright would pool secretions in the posterior basal segments. Supine with head elevated drains the superior segments. Side-lying drains the lateral basal segments of the dependent side.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "Posterior Basal Postural Drainage" },
  { id: "pta-b34-010", stem: "A PTA is treating a patient with a venous stasis ulcer on the medial aspect of the left lower leg. The wound has moderate serous exudate and a beefy red granulating wound bed. The patient's ankle-brachial index (ABI) is 0.92. Which compression therapy is MOST appropriate?", options: ["No compression due to the open wound", "Multi-layer compression bandaging system providing 30-40 mmHg of sustained compression to promote venous return and reduce edema", "Intermittent pneumatic compression at 80 mmHg for 4 hours continuously", "Elastic stockings at 10-15 mmHg only"], correctIndex: 1, rationale: "Venous stasis ulcers require compression therapy as the cornerstone of treatment. An ABI of 0.92 is normal (>0.8), indicating adequate arterial perfusion and safety for compression. Multi-layer compression at 30-40 mmHg is the evidence-based standard for venous ulcer management, improving venous return, reducing edema, and promoting healing. Withholding compression from a venous ulcer with adequate ABI delays healing. Intermittent pneumatic compression at 80 mmHg for 4 hours is excessive and impractical. Low compression (10-15 mmHg) elastic stockings are insufficient for ulcer healing and are more appropriate for prevention.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Venous Ulcer Compression Therapy" },
  { id: "pta-b34-011", stem: "A PTA is adjusting a knee-ankle-foot orthosis (KAFO) for a patient with quadriceps weakness following a femoral nerve injury. The patient reports the knee lock mechanism is difficult to unlock when transitioning from standing to sitting. The PTA should:", options: ["Instruct the patient to forcefully slam the lock mechanism", "Communicate the issue to the orthotist for adjustment of the knee lock mechanism, and in the interim teach the patient proper unlocking technique using weight shifting to unload the joint before attempting to unlock", "Remove the orthosis and have the patient ambulate without it", "Modify the orthosis by removing the knee lock entirely"], correctIndex: 1, rationale: "KAFO knee lock mechanisms can become difficult to operate if improperly adjusted, worn, or if the patient is not unloading the joint before attempting to unlock. The PTA should communicate mechanical issues to the orthotist for professional adjustment while teaching the patient proper technique: shift weight to the contralateral limb to unload the KAFO knee joint, then unlock. Forcefully slamming the mechanism risks damaging the orthosis and injuring the patient. Removing the orthosis removes necessary knee stability for a patient with quadriceps weakness. Removing the knee lock eliminates the stability feature that prevents knee buckling during stance.", difficulty: 1, category: "Prosthetics & Orthotics", topic: "KAFO Lock Mechanism Troubleshooting" },
  { id: "pta-b34-012", stem: "A PTA is monitoring a patient taking warfarin (Coumadin) for atrial fibrillation who presents for outpatient rehabilitation following a total knee replacement. The patient's INR today is 3.8 (therapeutic range 2.0-3.0). The PTA should:", options: ["Proceed with the treatment session as planned including aggressive range of motion and soft tissue mobilization", "Modify the treatment to avoid activities with high bleeding risk (aggressive ROM, deep tissue work, high-impact activities), notify the supervising PT, and recommend the patient contact their anticoagulation provider regarding the supratherapeutic INR", "Cancel all physical therapy sessions until the INR returns to normal", "Apply ice packs to all joints to prevent spontaneous bleeding"], correctIndex: 1, rationale: "An INR of 3.8 exceeds the therapeutic range (2.0-3.0), placing the patient at increased bleeding risk. The PTA should modify treatment by avoiding activities that could cause bleeding (aggressive ROM, deep tissue mobilization, high-impact exercises) while still providing beneficial therapy (gentle AROM, isometrics, gait training with precautions). The anticoagulation provider should be notified of the supratherapeutic INR. Proceeding without modification risks hemorrhage. Canceling all therapy is overly conservative when modified treatment is safe. Ice packs to all joints do not address the bleeding risk and are not indicated.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Supratherapeutic Warfarin INR" },
  { id: "pta-b34-013", stem: "A PTA is analyzing the biomechanics of a patient performing a deep squat. At the bottom of the squat, the patient's knees travel significantly anterior to the toes. This position creates:", options: ["Decreased patellofemoral joint compression forces and is biomechanically ideal", "Increased posterior cruciate ligament stress with no effect on patellofemoral forces", "Increased patellofemoral joint compression forces and increased demands on the quadriceps tendon, which may be problematic for patients with patellofemoral pain syndrome", "No change in joint forces compared to a squat where knees stay behind the toes"], correctIndex: 2, rationale: "When the knees travel significantly anterior to the toes during a deep squat, the moment arm between the ground reaction force and the knee joint center increases, creating greater knee extensor torque demand. This increases quadriceps tendon tension and patellofemoral joint compression forces (the patella is pressed more firmly into the trochlear groove). For healthy individuals this may be acceptable, but for patients with patellofemoral pain syndrome it can exacerbate symptoms. The position does not decrease patellofemoral forces. PCL stress is more related to posterior tibial translation forces. Joint forces are significantly altered by knee position relative to the toes.", difficulty: 2, category: "Biomechanics & Kinesiology", topic: "Squat Patellofemoral Forces" },
  { id: "pta-b34-014", stem: "A PTA is conducting a literature search and finds a systematic review with meta-analysis examining the effectiveness of therapeutic ultrasound for lateral epicondylalgia. This type of study design is considered:", options: ["The lowest level of evidence because it only summarizes other studies", "The highest level of evidence in the evidence hierarchy because it systematically synthesizes results from multiple studies, reducing bias and increasing precision of effect estimates", "Equal in evidence level to a single case report", "Inferior to expert opinion for clinical decision-making"], correctIndex: 1, rationale: "Systematic reviews with meta-analysis occupy the top of the evidence hierarchy (Level I evidence). They systematically identify, appraise, and synthesize results from multiple studies on a specific clinical question, using statistical methods (meta-analysis) to combine results. This approach reduces individual study biases, increases statistical power, and provides more precise effect estimates. A single case report is near the bottom of the evidence hierarchy. Expert opinion, while valuable, is the lowest level of formal evidence. Summarizing multiple studies with rigorous methodology is a strength, not a limitation.", difficulty: 1, category: "Evidence-Based Practice", topic: "Systematic Review Evidence Level" },
  { id: "pta-b34-015", stem: "A PTA is treating a patient with phantom limb pain following a transtibial amputation performed 3 weeks ago. The patient describes burning and cramping sensations in the missing foot. The MOST evidence-based intervention the PTA can provide is:", options: ["Telling the patient the pain is not real and will resolve on its own", "Mirror therapy, where the patient observes the intact limb's reflection while performing bilateral movements, creating a visual illusion of the missing limb moving pain-free", "Applying ultrasound to the residual limb stump only", "Complete rest and avoidance of all residual limb movement"], correctIndex: 1, rationale: "Mirror therapy has strong evidence for reducing phantom limb pain by addressing maladaptive cortical reorganization. The patient observes the reflection of the intact limb performing movements, creating a visual representation of the missing limb moving without pain. This visual feedback helps resolve the conflict between motor output and sensory feedback that contributes to phantom pain. Dismissing the pain as unreal is inappropriate; phantom limb pain involves real neurological mechanisms. Ultrasound to the stump does not address the central nervous system mechanisms driving phantom pain. Rest and movement avoidance can worsen cortical changes contributing to phantom pain.", difficulty: 2, category: "Pain Management", topic: "Mirror Therapy Phantom Limb Pain" },
  { id: "pta-b34-016", stem: "A PTA is treating a patient referred for pulmonary rehabilitation who has severe COPD with an FEV1 of 32% predicted. During the initial exercise session, the patient desaturates to 85% SpO2 during treadmill walking. The PTA should:", options: ["Discontinue pulmonary rehabilitation as the patient is too severe for exercise", "Reduce the exercise intensity, apply supplemental oxygen to maintain SpO2 above 88-90%, and continue with a modified exercise program using interval training if needed", "Increase the treadmill speed to build endurance more quickly", "Wait 15 minutes and recheck SpO2 without modifying the exercise"], correctIndex: 1, rationale: "Exercise-induced desaturation is common in severe COPD patients but does not preclude pulmonary rehabilitation. Supplemental oxygen should be titrated to maintain SpO2 at or above 88-90% during exercise. Interval training (alternating higher and lower intensity periods) is effective for severe COPD patients who cannot sustain continuous exercise. Severe COPD patients benefit significantly from pulmonary rehabilitation. Increasing speed would worsen desaturation. Waiting without intervention exposes the patient to prolonged hypoxemia. The exercise prescription should be modified to the patient's tolerance with appropriate oxygen support.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "COPD Exercise Desaturation Management" },
  { id: "pta-b34-017", stem: "A PTA is assessing a diabetic foot ulcer on the plantar surface of the first metatarsal head. The wound edges are rolled (epibole) and there is a thick callus ring surrounding the wound. The PTA should recognize that:", options: ["The rolled edges and callus indicate healthy wound progression", "The callus ring acts as a foreign body that increases pressure on the wound margins and impedes epithelial migration, requiring debridement by an appropriately credentialed clinician to promote healing", "The callus should be left intact as it provides natural wound protection", "Only the rolled edges need treatment; the callus is beneficial"], correctIndex: 1, rationale: "Epibole (rolled wound edges) and peri-wound callus formation are barriers to wound healing in diabetic foot ulcers. The callus ring increases focal pressure on wound margins (acting like a foreign body pressing into the tissue), and the rolled edges prevent epithelial cells from migrating across the wound bed. Debridement of the callus and wound edges by an appropriately credentialed clinician removes these barriers and converts a chronic wound to an acute wound environment, promoting healing. These findings do not indicate healthy progression. Leaving the callus intact perpetuates the pressure cycle that created the ulcer.", difficulty: 3, category: "Integumentary & Wound Care", topic: "Diabetic Ulcer Callus Epibole" },
  { id: "pta-b34-018", stem: "A PTA is fitting a patient with a custom molded ankle-foot orthosis (AFO) for foot drop secondary to peroneal nerve palsy. Upon initial fitting, the patient reports a pressure point over the fibular head. The PTA should:", options: ["Tell the patient to wear the AFO for a full week to allow the skin to toughen up", "Remove the AFO immediately, document the pressure area, and contact the orthotist for modification, as the fibular head is a bony prominence where sustained pressure can cause further peroneal nerve compression", "Add extra socks to cushion the pressure point", "Trim the AFO material over the fibular head with scissors"], correctIndex: 1, rationale: "Pressure over the fibular head is especially concerning in a patient with peroneal nerve palsy because additional compression at this site can worsen the nerve injury. The fibular head is a superficial bony prominence where the common peroneal nerve is vulnerable. The PTA should remove the AFO to prevent skin breakdown and nerve damage, document the issue, and refer to the orthotist for professional modification. Wearing through the discomfort risks pressure ulcer formation and further nerve damage. Extra socks do not adequately redistribute pressure and can alter the fit. The PTA should not modify orthotic devices; this is the orthotist's scope.", difficulty: 1, category: "Prosthetics & Orthotics", topic: "AFO Fibular Head Pressure" },
  { id: "pta-b34-019", stem: "A PTA is treating a patient who takes gabapentin (Neurontin) 900 mg three times daily for neuropathic pain. The patient reports dizziness, drowsiness, and difficulty with balance during therapy. The PTA should:", options: ["Attribute the symptoms to the patient's neurological condition and proceed with the normal treatment plan", "Recognize these as common side effects of gabapentin, implement fall prevention strategies during therapy (gait belt, close guarding, reduced balance challenge), and document the findings for communication with the prescribing provider", "Discontinue all therapy until the medication is changed", "Instruct the patient to stop taking gabapentin before therapy sessions"], correctIndex: 1, rationale: "Gabapentin commonly causes dizziness, drowsiness, ataxia, and peripheral edema, particularly at higher doses. These side effects directly impact fall risk and balance during therapy. The PTA should modify the treatment session to account for these effects by implementing fall prevention measures while still providing beneficial therapy. Attributing the symptoms solely to the neurological condition misses the medication contribution. Discontinuing therapy entirely is unnecessarily restrictive. The PTA cannot advise patients to stop prescribed medications; this is outside the PTA scope and potentially dangerous as abrupt gabapentin cessation can cause seizures.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Gabapentin Side Effects Balance" },
  { id: "pta-b34-020", stem: "A PTA is analyzing the force couple at the shoulder during arm elevation. The upward rotation force couple of the scapula consists of:", options: ["The upper trapezius pulling superiorly on the acromion, the lower trapezius pulling medially and inferiorly on the scapular spine, and the serratus anterior pulling the inferior angle laterally and anteriorly", "Only the deltoid and supraspinatus acting on the humerus", "The rhomboids and levator scapulae working together", "The pectoralis major and latissimus dorsi"], correctIndex: 0, rationale: "The scapular upward rotation force couple involves three muscles creating a rotational torque: the upper trapezius pulls superiorly on the lateral scapular spine/acromion, the lower trapezius pulls inferomedially on the medial scapular spine, and the serratus anterior pulls the inferior angle of the scapula laterally and anteriorly around the thorax. Together, these muscles rotate the glenoid fossa upward to maintain congruence with the humeral head during arm elevation. The deltoid and supraspinatus act on the humerus, not the scapula. The rhomboids and levator scapulae produce downward rotation. The pectoralis major and latissimus dorsi are humeral adductors/extensors.", difficulty: 2, category: "Biomechanics & Kinesiology", topic: "Scapular Upward Rotation Force Couple" },
  { id: "pta-b34-021", stem: "A PTA is reading a clinical practice guideline for the management of Achilles tendinopathy. The guideline rates eccentric exercise as having 'Grade A' (strong) evidence. This rating means:", options: ["The recommendation is based on a single expert's opinion", "The recommendation is supported by consistent findings from multiple high-quality randomized controlled trials or a systematic review of RCTs", "The evidence is preliminary and based on animal studies only", "The recommendation is based on common clinical practice without formal research support"], correctIndex: 1, rationale: "In most evidence grading systems (GRADE, Oxford, etc.), Grade A represents the strongest level of recommendation, typically supported by consistent evidence from multiple well-designed RCTs or high-quality systematic reviews/meta-analyses. This indicates high confidence that the recommendation reflects the true treatment effect. A single expert opinion corresponds to the lowest evidence level (Grade D or similar). Animal studies would not support a Grade A clinical recommendation. Practice-based recommendations without formal research correspond to Grade C or D evidence levels.", difficulty: 1, category: "Evidence-Based Practice", topic: "Evidence Grading Systems" },
  { id: "pta-b34-022", stem: "A PTA is treating a patient with central sensitization presenting as widespread pain, allodynia (pain from non-painful stimuli), and hyperalgesia. The patient rates light touch on the forearm as 6/10 pain. The MOST appropriate treatment approach is:", options: ["Applying deep friction massage to the painful forearm to desensitize the tissue", "A graded exposure approach starting with stimuli the patient can tolerate (e.g., fabric textures, air currents) and progressively increasing the intensity, combined with pain neuroscience education to address the central amplification", "Avoiding all sensory input to the affected areas indefinitely", "Using maximum intensity TENS directly over the allodynic area"], correctIndex: 1, rationale: "Central sensitization involves amplified central nervous system processing where normally non-painful stimuli are perceived as painful. Graded exposure (systematic desensitization) starts with tolerable stimuli and progressively increases intensity, allowing the nervous system to recalibrate its threat assessment. Pain neuroscience education helps the patient understand that the pain reflects nervous system amplification rather than tissue damage. Deep friction massage on an allodynic area would dramatically increase pain and reinforce central sensitization. Avoiding all input perpetuates the sensitization. Maximum intensity TENS on an allodynic area could be perceived as extremely painful.", difficulty: 3, category: "Pain Management", topic: "Central Sensitization Desensitization" },
  { id: "pta-b34-023", stem: "A PTA has three patients scheduled simultaneously at 10:00 AM: Patient A is a post-op total hip replacement day 2 needing first ambulation, Patient B is a chronic low back pain patient in week 6 of a progressive exercise program, and Patient C is an outpatient with shoulder impingement awaiting a hot pack before exercises. The PTA should:", options: ["See Patient B first because they have been waiting the longest in their care plan", "Prioritize Patient A (post-op THR first ambulation) as this patient has the highest medical acuity and time-sensitive mobility needs, delegate the hot pack application for Patient C, then see Patient B who can begin independent warm-up exercises", "Cancel all three appointments and reschedule for different times", "See Patient C first because the hot pack takes the least time to apply"], correctIndex: 1, rationale: "Clinical prioritization requires assessing medical acuity, time sensitivity, and patient safety. Patient A (post-op day 2 THR, first ambulation) has the highest acuity: delayed mobilization increases DVT, pneumonia, and deconditioning risk. Early ambulation is a critical time-sensitive intervention. Patient C's hot pack can be delegated or applied quickly as a passive modality. Patient B can begin independent warm-up exercises from their established program. Seeing patients based on program duration rather than acuity is inappropriate. Canceling all appointments when workflow management can accommodate them is unnecessary.", difficulty: 1, category: "Clinical Prioritization & Workflow", topic: "Multi-Patient Acuity Prioritization" },
  { id: "pta-b34-024", stem: "A PTA is performing auscultation on a patient in the ICU and hears bilateral coarse crackles in the lower lung fields that clear partially with coughing. The patient has a productive cough with thick yellow sputum. These findings are MOST consistent with:", options: ["Pneumothorax", "Pleural effusion without infection", "Retained airway secretions or bronchitis, where the crackles represent air passing through airways partially obstructed by mucus", "Normal lung sounds in a healthy adult"], correctIndex: 2, rationale: "Coarse crackles (low-pitched, bubbling sounds) that partially clear with coughing indicate secretions in the larger airways. Combined with productive cough and thick yellow sputum, this presentation is consistent with retained secretions or infectious bronchitis. The fact that crackles partially clear with coughing confirms the mobile, secretion-based nature. Pneumothorax produces diminished or absent breath sounds, not crackles. Pleural effusion typically presents with diminished breath sounds and dullness to percussion, not crackles that clear with coughing. Normal lung sounds are clear without adventitious sounds.", difficulty: 1, category: "Cardiopulmonary Physical Therapy", topic: "Coarse Crackles Secretion Retention" },
  { id: "pta-b34-025", stem: "A PTA is treating a patient with a full-thickness burn on the anterior chest and bilateral upper extremities. The patient is 5 days post-burn and the wounds are being managed with silver sulfadiazine cream and gauze dressings. The PTA's MOST important positioning recommendation is:", options: ["Keep the upper extremities adducted and internally rotated at the shoulders for comfort", "Position the patient with shoulders abducted to 90 degrees, elbows extended, wrists in neutral to slight extension, and the neck in neutral or slight extension to prevent contracture formation in the anti-deformity position", "Allow the patient to assume whatever position is most comfortable", "Position all burned extremities in maximum flexion"], correctIndex: 1, rationale: "Full-thickness burns contract toward flexion and adduction during healing. Anti-deformity positioning opposes the expected contracture pattern: anterior chest burns tend toward shoulder adduction/protraction, so shoulders should be positioned in abduction (90 degrees); elbow burns flex, so elbows are positioned in extension; wrist burns flex, so wrists are positioned in neutral to slight extension. Neck burns pull into flexion, so the neck should be neutral or slightly extended. Comfort positions (adduction, flexion) allow contractures to develop. Allowing any position neglects contracture prevention. Maximum flexion promotes the exact contracture pattern the positioning is designed to prevent.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Burn Anti-Deformity Positioning" },
  { id: "pta-b34-026", stem: "A patient with a below-knee amputation has been wearing a patellar tendon bearing (PTB) prosthetic socket. The patient complains of pain and redness over the tibial crest and fibular head but good comfort over the patellar tendon and medial tibial flare. This indicates:", options: ["The socket is fitting correctly with appropriate weight distribution", "Excessive pressure on pressure-tolerant areas", "Inadequate relief over pressure-sensitive bony prominences (tibial crest and fibular head) in the socket design, while the pressure-tolerant areas (patellar tendon, medial tibial flare) are bearing weight appropriately", "The prosthesis is too loose overall"], correctIndex: 2, rationale: "PTB socket design distributes weight-bearing forces to pressure-tolerant areas (patellar tendon, medial tibial flare, popliteal fossa) while providing relief (less contact) over pressure-sensitive bony prominences (tibial crest, fibular head, distal tibia, hamstring tendons). Pain and redness over the tibial crest and fibular head with comfort at the patellar tendon and medial tibial flare indicates the socket lacks adequate relief over the bony prominences. The prosthetist needs to modify the socket to add relief in these areas. The socket is not fitting correctly if there is pain over bony areas. The pressure-tolerant areas are functioning well, not receiving excessive pressure.", difficulty: 3, category: "Prosthetics & Orthotics", topic: "PTB Socket Pressure Distribution" },
  { id: "pta-b34-027", stem: "A PTA is treating a patient who recently started taking a statin medication (atorvastatin) for hypercholesterolemia. The patient reports new onset of bilateral calf muscle pain and weakness that started two weeks after beginning the medication. The PTA should:", options: ["Dismiss the symptoms as normal exercise soreness", "Recognize this as a potential statin-induced myopathy, modify the exercise program to reduce muscle strain, and communicate the finding to the supervising PT for referral back to the prescribing physician for creatine kinase (CK) level assessment", "Instruct the patient to double the statin dose to overcome the side effects", "Prescribe ibuprofen to manage the muscle pain"], correctIndex: 1, rationale: "Statins (atorvastatin, simvastatin, rosuvastatin) can cause myopathy ranging from mild myalgia to severe rhabdomyolysis. Bilateral muscle pain and weakness beginning shortly after starting statin therapy is a classic presentation. The PTA should recognize this temporal relationship, modify exercise to avoid worsening muscle damage, and communicate to the healthcare team for CK level assessment. Elevated CK confirms muscle damage requiring potential dose adjustment or medication change. Dismissing the symptoms could allow progression to rhabdomyolysis. The PTA cannot adjust medication doses or prescribe medications. Early recognition of statin myopathy is critical for patient safety.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Statin-Induced Myopathy Recognition" },
  { id: "pta-b34-028", stem: "A PTA is teaching a patient about the biomechanics of lifting. When a patient holds a 20-pound box at arm's length (approximately 18 inches from the spine) versus close to the body (approximately 6 inches from the spine), the load on the lumbar spine:", options: ["Remains the same regardless of the distance from the body", "Decreases when the box is held at arm's length due to counterbalancing", "Increases approximately three-fold when held at arm's length because the external moment arm is tripled, requiring proportionally greater erector spinae force and resulting in greater compressive loading on the lumbar discs", "Only changes if the box weighs more than 50 pounds"], correctIndex: 2, rationale: "Spinal loading follows lever mechanics. The lumbar spine acts as a fulcrum, and the external load creates a torque equal to the load multiplied by its distance from the spine (moment arm). At 18 inches, the moment arm is three times that at 6 inches, creating three times the external torque. The erector spinae muscles must generate proportionally greater force to counterbalance this torque. Because these muscles have a short moment arm (approximately 2 inches from the spine), the compressive force on the lumbar discs is multiplied dramatically. This principle applies to any load weight, not just heavy objects. Holding loads close to the body is a fundamental body mechanics principle for reducing spinal loading.", difficulty: 1, category: "Biomechanics & Kinesiology", topic: "Lifting Moment Arms Spinal Load" },
  { id: "pta-b34-029", stem: "A PTA is designing a home exercise program and wants to ensure the exercises have the best evidence for reducing fall risk in community-dwelling older adults. According to the current best evidence, the MOST effective exercise component for fall prevention is:", options: ["Upper extremity strengthening with dumbbells", "Walking programs alone without other exercise components", "Balance and functional training that specifically challenges postural control, such as tandem stance, single-leg stance, Tai Chi, and perturbation-based training", "Passive stretching of the lower extremities three times weekly"], correctIndex: 2, rationale: "Strong evidence from multiple systematic reviews and meta-analyses (including the Cochrane review on fall prevention) identifies balance and functional training that specifically challenges postural control as the most effective exercise component for reducing fall rates in community-dwelling older adults. Tai Chi, perturbation-based training, and progressive balance exercises show the strongest effect sizes. Upper extremity strengthening alone does not address the balance deficits underlying falls. Walking programs reduce fall risk modestly but are less effective than targeted balance training. Passive stretching does not challenge postural control systems and has minimal evidence for fall prevention.", difficulty: 2, category: "Evidence-Based Practice", topic: "Fall Prevention Exercise Evidence" },
  { id: "pta-b34-030", stem: "A PTA is treating a patient with fibromyalgia who reports widespread pain, fatigue, and sleep disturbance. The patient expresses frustration that previous therapy focused only on stretching with no improvement. The MOST appropriate exercise modification is:", options: ["Discontinue all exercise as the patient clearly cannot tolerate physical activity", "Implement a low-to-moderate intensity aerobic exercise program (aquatic or land-based), starting below the patient's symptom threshold and gradually progressing, as aerobic exercise has the strongest evidence for reducing fibromyalgia pain and improving function", "Prescribe high-intensity plyometric training to override the pain signals", "Maintain the same stretching-only program for another 12 weeks"], correctIndex: 1, rationale: "Aerobic exercise has the strongest evidence base for fibromyalgia management, demonstrating improvements in pain, fatigue, physical function, and sleep quality. The key is starting below the symptom exacerbation threshold and progressing gradually (the 'start low, go slow' principle). Aquatic exercise may be particularly beneficial due to buoyancy, warmth, and reduced joint stress. Discontinuing exercise eliminates the most effective non-pharmacological intervention. High-intensity plyometrics would likely trigger symptom flares and exercise avoidance. Continuing an ineffective stretching-only program ignores the evidence for aerobic exercise and fails to address the patient's lack of progress.", difficulty: 2, category: "Pain Management", topic: "Fibromyalgia Aerobic Exercise" },
  { id: "pta-b34-031", stem: "A PTA in a skilled nursing facility needs to document and bill for services provided to three Medicare Part A patients. The PTA recalls that documentation must support medical necessity and skilled care. Which scenario represents an appropriate skilled service that the PTA can provide and bill for?", options: ["Supervising a patient performing an independent home exercise program that was fully established 4 weeks ago with no modifications", "Providing progressive resistive exercises to a patient following hip fracture repair, adjusting resistance and monitoring form as the patient advances through the rehabilitation protocol under the PT's plan of care", "Applying a hot pack to a patient's shoulder without any other skilled intervention during the session", "Walking with a patient who ambulates independently for general fitness"], correctIndex: 1, rationale: "Skilled services under Medicare require the unique skills of a trained therapist, cannot be safely performed by unskilled personnel, and must be part of a plan of care. Progressive resistive exercise with ongoing adjustment and clinical monitoring meets skilled care criteria. Supervising an already-established independent HEP without modifications does not require skilled intervention. A hot pack alone without skilled treatment does not constitute a skilled service. Walking with an independent ambulator for general fitness is maintenance-level and does not require PTA skills. Documentation must demonstrate the complexity and clinical judgment involved.", difficulty: 2, category: "Clinical Prioritization & Workflow", topic: "Medicare Skilled Service Documentation" },
  { id: "pta-b34-032", stem: "A PTA is performing six-minute walk test (6MWT) monitoring on a patient with congestive heart failure (NYHA Class III). During the test, the patient develops a persistent cough with frothy pink-tinged sputum. This finding is MOST concerning for:", options: ["Normal exercise-induced bronchospasm", "Acute pulmonary edema indicating decompensated heart failure, requiring immediate cessation of the test and emergency medical intervention", "Mild upper respiratory infection", "Gastroesophageal reflux during exercise"], correctIndex: 1, rationale: "Frothy pink-tinged sputum during exertion in a patient with CHF is a hallmark sign of acute pulmonary edema. The pink tinge indicates blood mixing with edema fluid in the alveoli as elevated left ventricular pressures cause fluid transudation into the pulmonary interstitium and alveoli. This is a medical emergency requiring immediate test cessation, positioning the patient upright to reduce venous return, calling for emergency assistance, and monitoring vital signs. Exercise-induced bronchospasm produces wheezing, not frothy pink sputum. Upper respiratory infection does not produce frothy pink sputum acutely during exercise. GERD does not cause pink-tinged pulmonary secretions.", difficulty: 3, category: "Cardiopulmonary Physical Therapy", topic: "CHF Acute Pulmonary Edema Signs" },
  { id: "pta-b34-033", stem: "A PTA is performing wound measurements on a tunneling wound. The wound opening on the skin surface measures 2 cm x 1.5 cm, but when the PTA gently inserts a sterile cotton-tipped applicator into a tract at the 3 o'clock position, it extends 4 cm beneath the intact skin surface. The PTA should document this as:", options: ["A 2 cm x 1.5 cm wound with undermining at 3 o'clock", "A 2 cm x 1.5 cm wound with a 4 cm tunnel (sinus tract) at the 3 o'clock position, using the clock method with 12 o'clock oriented toward the patient's head", "A 6 cm x 1.5 cm wound, adding the tunnel length to the surface measurement", "A 2 cm x 1.5 cm superficial wound with no additional notation"], correctIndex: 1, rationale: "Tunneling (sinus tract) is a channel that extends from the wound bed through subcutaneous tissue, creating a passage beneath intact skin. It is documented separately from the surface wound dimensions using the clock method (12 o'clock toward the patient's head). The measurement includes the depth of penetration (4 cm) and the clock position (3 o'clock). Undermining is different from tunneling: undermining is tissue destruction under intact wound edges extending in multiple directions, while tunneling is a discrete narrow tract. Adding tunnel length to surface measurements misrepresents the wound dimensions. Failing to document the tunnel misses critical wound assessment data.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Wound Tunneling Documentation" },
  { id: "pta-b34-034", stem: "A PTA is providing gait training for a patient with a unilateral transtibial prosthesis on level ground. The patient demonstrates an abducted gait pattern (wide-based gait with the prosthetic limb circumducting laterally). Assuming the prosthesis fits properly, the PTA should focus training on:", options: ["Increasing prosthetic-side step length only", "Weight-shifting exercises to improve confidence bearing weight on the prosthetic limb, single-leg stance balance on the prosthetic side, and narrowing the base of support gradually during gait training", "Running drills to improve gait speed", "Stair climbing before correcting the level-ground gait deviation"], correctIndex: 1, rationale: "An abducted gait pattern in a properly fitting prosthesis typically results from fear or lack of confidence bearing weight on the prosthetic side, leading to rapid weight transfer and lateral compensation. The PTA should address the root cause through weight-shifting exercises (building confidence in prosthetic-side weight acceptance), single-leg balance on the prosthetic side (progressive trust-building), and gradually narrowing the base of support during gait. Focusing only on step length does not address the abduction pattern. Running drills are premature before correcting fundamental gait deviations. Stair climbing should follow mastery of level-ground gait patterns.", difficulty: 2, category: "Prosthetics & Orthotics", topic: "Prosthetic Abducted Gait Training" },
  { id: "pta-b34-035", stem: "A PTA is treating a patient taking alendronate (Fosamax) for osteoporosis. The patient mentions taking the medication with breakfast and then lying down for a nap. The PTA should:", options: ["Commend the patient for remembering to take the medication", "Educate the patient that bisphosphonates must be taken on an empty stomach with a full glass of plain water, and the patient must remain upright (sitting or standing) for at least 30 minutes afterward to prevent esophageal irritation and ulceration", "Suggest the patient take the medication at bedtime instead", "Advise the patient to crush the tablet and mix it with food for better absorption"], correctIndex: 1, rationale: "Bisphosphonates (alendronate, risedronate) have strict administration requirements to prevent esophageal irritation, ulceration, and stricture: take on an empty stomach first thing in the morning, swallow whole with a full glass (8 oz) of plain water (not juice, coffee, or milk which reduce absorption), and remain upright for at least 30 minutes. Lying down after taking the medication allows the tablet to contact the esophageal mucosa, causing chemical irritation. Taking with food significantly reduces absorption (by up to 60%). Bedtime administration with subsequent lying down is specifically contraindicated. Crushing the tablet can cause oral mucosal irritation.", difficulty: 1, category: "Pharmacology for PTAs", topic: "Bisphosphonate Administration Safety" },
  { id: "pta-b34-036", stem: "During gait analysis, a PTA observes that a patient with weak hip abductors on the right demonstrates a compensatory contralateral pelvic drop (left side drops) during right-sided stance phase. This clinical finding is called:", options: ["Antalgic gait pattern", "Trendelenburg sign, indicating that the right gluteus medius is insufficient to stabilize the pelvis during single-limb stance on the right, allowing the unsupported left side to drop", "Steppage gait", "Circumduction gait"], correctIndex: 1, rationale: "The Trendelenburg sign occurs when the hip abductors (primarily gluteus medius) on the stance limb are weak and unable to maintain the pelvis level during single-limb support. The contralateral (swing-side) pelvis drops because the stance-side abductors cannot counteract the gravitational torque on the unsupported side. Antalgic gait is a pain-avoidance pattern with shortened stance phase. Steppage gait involves excessive hip and knee flexion to clear a foot drop. Circumduction gait involves swinging the leg laterally in a semicircle to clear the foot. The compensatory Trendelenburg gait (lateral trunk lean toward the weak side) is also seen when patients lean to reduce the demand on weak abductors.", difficulty: 1, category: "Biomechanics & Kinesiology", topic: "Trendelenburg Sign Biomechanics" },
  { id: "pta-b34-037", stem: "A PTA is evaluating the methodological quality of an RCT on manual therapy for cervical radiculopathy. The study did not blind the treating therapists or the patients. The PTA should recognize that this limitation:", options: ["Has no impact on the study's internal validity", "Introduces performance bias (therapists may unconsciously treat groups differently) and expectation bias (patients in the treatment group may report better outcomes due to knowing they received the intervention), but blinding is often impractical in physical therapy research", "Makes the study completely invalid and unusable for clinical practice", "Only affects external validity, not internal validity"], correctIndex: 1, rationale: "Lack of blinding in physical therapy research introduces performance bias (therapists may provide differential care) and expectation/placebo effects (patients who know their group assignment may report differently). However, blinding is often impractical or impossible in manual therapy and exercise studies because both the therapist and patient can identify the treatment. This is a recognized limitation of physical therapy RCTs, not a reason to dismiss findings entirely. The limitation affects internal validity (the ability to attribute outcomes to the intervention), not just external validity. Readers should consider this bias when interpreting results but recognize the pragmatic constraints of rehabilitation research.", difficulty: 3, category: "Evidence-Based Practice", topic: "Blinding Limitations in PT Research" },
  { id: "pta-b34-038", stem: "A PTA is implementing a pain management strategy for a patient with chronic neck pain who demonstrates fear-avoidance beliefs and kinesiophobia (fear of movement). The patient avoids all neck rotation due to fear of re-injury. An evidence-based approach includes:", options: ["Reinforcing the patient's movement avoidance to prevent potential re-injury", "Graded activity exposure beginning with small, safe neck movements within pain-free ranges, progressively increasing range and load while providing reassurance and education that movement is safe and beneficial", "Cervical collar immobilization for 6 weeks to allow complete healing before any movement", "Passive treatments only (ultrasound, TENS) with no active movement component"], correctIndex: 1, rationale: "Fear-avoidance beliefs and kinesiophobia are strong predictors of chronic pain disability. Graded activity exposure systematically challenges avoidance behaviors by introducing feared movements in a safe, controlled, progressive manner. Beginning within pain-free ranges demonstrates safety and builds confidence, while gradual progression reconditions the patient physically and psychologically. Education that movement is safe and beneficial addresses the cognitive component. Reinforcing avoidance perpetuates the fear-avoidance cycle. Cervical collar immobilization promotes deconditioning and reinforces the belief that the neck is fragile. Passive-only treatments without active movement do not address the core issue of movement avoidance.", difficulty: 2, category: "Pain Management", topic: "Kinesiophobia Graded Exposure" },
  { id: "pta-b34-039", stem: "A PTA is working with a patient in acute care who was admitted for community-acquired pneumonia. The physician has ordered physical therapy for early mobilization. On assessment, the patient has bilateral rhonchi, SpO2 of 91% on 3L nasal cannula, temperature of 101.2°F, heart rate of 98 bpm, and respiratory rate of 22. The PTA should:", options: ["Defer all treatment until the patient is afebrile and all vital signs are completely normal", "Proceed with graded early mobilization (seated edge of bed progressing to standing and ambulation as tolerated) while monitoring SpO2, vital signs, and symptoms, ensuring SpO2 remains above 88% and adjusting supplemental oxygen as needed per protocol", "Perform vigorous chest physiotherapy including postural drainage in Trendelenburg positions", "Ambulate the patient in the hallway without supplemental oxygen to encourage lung expansion"], correctIndex: 1, rationale: "Early mobilization in pneumonia patients improves outcomes including shorter hospital stays and reduced functional decline. The patient's vital signs (mild tachycardia, low-grade fever, mild tachypnea) are within acceptable parameters for graded mobilization with monitoring. Waiting for completely normal vitals would significantly delay beneficial early mobilization. Vigorous chest physiotherapy in Trendelenburg may be poorly tolerated in acute pneumonia with fever and borderline oxygen saturation. Removing supplemental oxygen during ambulation risks dangerous desaturation. The PTA should monitor SpO2 continuously during activity and maintain it above 88%, adjusting activity intensity accordingly.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "Pneumonia Early Mobilization" },
  { id: "pta-b34-040", stem: "A PTA is assessing a wound on a patient's heel and notes the wound base is covered with black, hard, dry tissue that is firmly adherent to the wound bed. This tissue is classified as:", options: ["Granulation tissue indicating healthy wound healing", "Eschar, which is necrotic (dead) tissue that must be assessed by the physician or wound specialist to determine if debridement is indicated, particularly in the heel where stable dry eschar may serve as a biological cover in the absence of infection", "A normal callus formation", "Fibrin slough requiring only moisture application"], correctIndex: 1, rationale: "Black, hard, dry, adherent tissue on a wound is eschar (necrotic tissue). In most wound locations, eschar is debrided to promote healing. However, stable dry eschar on the heel is a unique exception: per CMS guidelines, stable, dry, intact heel eschar without signs of infection (erythema, fluctuance, drainage, odor) may be left intact as it serves as a natural biological cover. The PTA should assess for infection signs and communicate findings to the wound care team. Granulation tissue is beefy red and moist, not black and dry. Callus forms on intact skin, not wound beds. Slough is yellow/tan and soft, not black and hard.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Eschar Assessment Heel Exception" },
  { id: "pta-b34-041", stem: "A PTA is fabricating a resting hand splint for a patient with rheumatoid arthritis affecting the wrist and metacarpophalangeal (MCP) joints. The optimal position for the resting hand splint is:", options: ["Wrist in full flexion, MCPs in full extension, IPs in full extension", "Wrist in 20-30 degrees extension, MCPs in 45-60 degrees flexion, IPs in slight flexion, and the thumb in palmar abduction, maintaining the functional position while reducing joint stress", "Wrist in maximum ulnar deviation, MCPs in maximum radial deviation", "All joints in full flexion to match the patient's current deformity pattern"], correctIndex: 1, rationale: "The resting hand splint for rheumatoid arthritis maintains joints in the functional (intrinsic plus) position: wrist in 20-30 degrees extension (optimal tendon mechanics), MCPs in 45-60 degrees flexion (collateral ligament tension prevents contracture), IPs in slight flexion (comfortable resting position), and thumb in palmar abduction (opposition readiness). This position balances joint protection with functional positioning. Wrist flexion and MCP extension (intrinsic minus position) promotes joint deformity. Ulnar deviation accentuates the common RA deformity pattern. Splinting into the deformity pattern reinforces pathological positioning rather than counteracting it.", difficulty: 2, category: "Prosthetics & Orthotics", topic: "RA Resting Hand Splint Position" },
  { id: "pta-b34-042", stem: "A PTA is treating a patient who takes prednisone (a corticosteroid) 20 mg daily for rheumatoid arthritis. When planning the exercise program, the PTA should consider that long-term corticosteroid use causes:", options: ["Increased bone density and improved healing", "Decreased bone density (steroid-induced osteoporosis), impaired wound healing, muscle weakness (steroid myopathy), thin fragile skin susceptible to bruising, and increased infection risk, all of which require exercise and handling modifications", "No effects relevant to physical therapy", "Only gastrointestinal side effects with no musculoskeletal impact"], correctIndex: 1, rationale: "Long-term corticosteroid use produces multiple effects relevant to physical therapy: steroid-induced osteoporosis (inhibits osteoblast function, increases fracture risk requiring impact modification), impaired wound healing (inhibits collagen synthesis and inflammatory response), steroid myopathy (proximal muscle weakness), thin fragile skin (increased bruising and tearing risk requiring gentle handling), and immunosuppression (increased infection risk requiring vigilant hygiene). Corticosteroids decrease, not increase, bone density. These effects have significant implications for exercise prescription, manual techniques, and patient handling. Musculoskeletal effects are among the most significant long-term consequences.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Long-Term Corticosteroid Effects" },
  { id: "pta-b34-043", stem: "A PTA is analyzing the biomechanics of the subtalar joint during the gait cycle. During the contact phase of gait, the subtalar joint normally moves into:", options: ["Supination to provide a rigid lever for push-off", "Pronation, which unlocks the midtarsal joints creating a flexible foot that accommodates uneven terrain and absorbs impact forces", "Neither pronation nor supination; the subtalar joint is fixed during gait", "Dorsiflexion and plantarflexion only"], correctIndex: 1, rationale: "During the contact phase (heel strike to foot flat), the subtalar joint pronates. This pronation unlocks the transverse tarsal (midtarsal) joints (Chopart's joint), creating a flexible, mobile foot that adapts to the terrain surface and absorbs ground reaction forces. Later in stance (midstance to push-off), the subtalar joint supinates, locking the midtarsal joints to create a rigid lever for efficient propulsion. Supination during contact would create a rigid foot that cannot absorb impact. The subtalar joint is not fixed during gait. The subtalar joint primarily performs pronation/supination (triplanar motion), not isolated dorsiflexion/plantarflexion.", difficulty: 2, category: "Biomechanics & Kinesiology", topic: "Subtalar Pronation Contact Phase" },
  { id: "pta-b34-044", stem: "A PTA is applying the concept of number needed to treat (NNT) from a research study. A study comparing manual therapy plus exercise versus exercise alone for adhesive capsulitis found that the NNT is 4 for achieving clinically meaningful improvement. This means:", options: ["Four patients experienced adverse effects from the treatment", "For every 4 patients treated with manual therapy plus exercise instead of exercise alone, 1 additional patient will achieve clinically meaningful improvement beyond what exercise alone would provide", "The treatment must be applied 4 times before any effect is seen", "Only 4% of patients respond to the treatment"], correctIndex: 1, rationale: "Number needed to treat (NNT) represents the number of patients who need to receive a treatment for one additional patient to benefit compared to the control group. An NNT of 4 means that for every 4 patients who receive manual therapy plus exercise, 1 additional patient achieves a clinically meaningful outcome beyond what exercise alone would produce. Lower NNTs indicate more effective treatments (NNT of 1 means every patient benefits). NNT does not relate to adverse effects (that is number needed to harm, NNH). It does not refer to treatment frequency. It represents a proportion of additional responders, not percentage response rate.", difficulty: 3, category: "Evidence-Based Practice", topic: "Number Needed to Treat Interpretation" },
  { id: "pta-b34-045", stem: "A PTA is treating a patient with chronic low back pain using a biopsychosocial approach. The patient has a sedentary desk job and reports pain increasing throughout the workday. Activity pacing as a pain management strategy involves:", options: ["Pushing through all pain to complete work tasks in the morning, then resting the entire afternoon", "Breaking activities into manageable segments with scheduled rest breaks or position changes BEFORE pain escalates, maintaining a consistent activity level throughout the day rather than following a boom-bust cycle", "Avoiding all desk work until the pain completely resolves", "Only performing activities when pain is at 0/10"], correctIndex: 1, rationale: "Activity pacing is a self-management strategy that prevents the boom-bust cycle (overactivity on good days leading to pain flares and inactivity on bad days). It involves pre-planned activity segments with scheduled rest or position changes based on time, not pain level. This maintains a consistent baseline of activity that can be gradually increased. Pushing through pain until forced to stop is the boom pattern that leads to pain flares and prolonged recovery. Avoiding all activity until pain-free promotes deconditioning and disability. Waiting for 0/10 pain is unrealistic in chronic pain and reinforces pain-contingent behavior that limits function.", difficulty: 2, category: "Pain Management", topic: "Activity Pacing Strategy" },
  { id: "pta-b34-046", stem: "A PTA is reviewing a patient's chart before treatment and notes the patient has a Do Not Resuscitate (DNR) order. During the therapy session in the gym, the patient becomes unresponsive and stops breathing. The PTA should:", options: ["Begin CPR immediately regardless of the DNR order", "Activate the emergency response system, stay with the patient, maintain airway positioning, and provide comfort measures but do NOT initiate CPR or use an AED, as the DNR order directs", "Leave the patient and continue treating other patients", "Attempt CPR for 2 minutes only, then stop"], correctIndex: 1, rationale: "A DNR order specifically directs that cardiopulmonary resuscitation (chest compressions, defibrillation, intubation, cardiac medications) should NOT be performed if the patient experiences cardiac or respiratory arrest. The PTA should activate the emergency response system so medical personnel can respond and confirm the situation, stay with the patient, maintain comfort, and keep the airway positioned. Starting CPR contradicts the legal medical order. Leaving the patient alone is abandonment. Partial CPR still violates the DNR. DNR does not mean 'do not treat'; the patient should still receive all other appropriate medical care.", difficulty: 1, category: "Clinical Prioritization & Workflow", topic: "DNR Order Response Protocol" },
  { id: "pta-b34-047", stem: "A PTA is performing incentive spirometry training with a post-operative patient following abdominal surgery. The patient is having difficulty achieving adequate inspiratory volume. The PTA should instruct the patient to:", options: ["Take rapid, shallow breaths into the spirometer", "Exhale forcefully into the spirometer first, then inhale", "Sit upright, seal lips around the mouthpiece, inhale slowly and deeply through the mouth sustaining the inspiratory effort for 3-5 seconds, hold the breath for 3-5 seconds at peak inspiration, then exhale normally and repeat 10 times every hour while awake", "Use the spirometer only once daily at maximum effort"], correctIndex: 2, rationale: "Proper incentive spirometry technique requires: upright positioning (reduces abdominal organ pressure on the diaphragm), slow sustained inhalation (allows maximal alveolar recruitment), breath hold at peak inspiration (sustains alveolar inflation and promotes collateral ventilation to prevent atelectasis), and frequent repetition (10 repetitions every 1-2 hours while awake). Rapid shallow breaths do not achieve alveolar recruitment. The device is designed for inhalation, not exhalation. Once-daily use is insufficient to prevent post-operative pulmonary complications (atelectasis, pneumonia). The sustained slow inspiration differentiates effective incentive spirometry from ineffective rapid efforts.", difficulty: 1, category: "Cardiopulmonary Physical Therapy", topic: "Incentive Spirometry Technique" },
  { id: "pta-b34-048", stem: "A PTA is managing a patient with a negative pressure wound therapy (NPWT/wound VAC) device on a large abdominal wound. The device alarm sounds indicating a leak. The PTA should:", options: ["Ignore the alarm and continue with the exercise session", "Assess the dressing seal around the wound for breaks or wrinkles in the adhesive drape, smooth any wrinkles, and ensure all tubing connections are secure; if the leak cannot be resolved, contact the wound care nurse or supervising PT", "Remove the entire NPWT dressing and replace it with dry gauze", "Turn off the NPWT device permanently and notify the surgeon"], correctIndex: 1, rationale: "NPWT device alarms typically indicate a loss of seal resulting in inability to maintain the prescribed negative pressure. The PTA should systematically troubleshoot: check the adhesive drape for wrinkles, gaps, or breaks in the seal (most common cause); verify all tubing connections are tight and not kinked; ensure the canister is properly seated. Many seal breaks can be corrected by smoothing wrinkles or applying additional adhesive strips. Ignoring the alarm means the wound is not receiving therapeutic negative pressure. Removing the dressing is beyond the PTA's scope and wastes a costly dressing. Permanently turning off the device requires a physician order.", difficulty: 2, category: "Integumentary & Wound Care", topic: "NPWT Leak Troubleshooting" },
  { id: "pta-b34-049", stem: "A patient with a transtibial amputation has been wearing a prosthesis for 3 months and reports that the socket feels loose, especially later in the day. The residual limb has decreased in circumference by 1.5 cm since the initial fitting. This is MOST likely due to:", options: ["An allergic reaction to the socket material causing tissue shrinkage", "Continued residual limb volume reduction (maturation) as post-amputation edema resolves and soft tissue atrophy occurs, which is expected in the first 12-18 months and requires socket modification or replacement", "A manufacturing defect in the prosthetic socket", "The patient losing weight from their residual limb due to excessive exercise"], correctIndex: 1, rationale: "Residual limb volume reduction is expected during the first 12-18 months post-amputation as post-surgical edema resolves, muscle atrophy occurs in denervated tissue, and soft tissue remodels. This maturation process causes progressive socket loosening, particularly noticeable later in the day when any remaining edema fluctuates. Additional socks can temporarily compensate for volume loss, but eventually socket modification or replacement is needed. Allergic reactions cause swelling, not shrinkage. Manufacturing defects would be apparent from the initial fitting. While exercise can affect limb volume, the 3-month timeline and gradual nature point to normal maturation.", difficulty: 1, category: "Prosthetics & Orthotics", topic: "Residual Limb Volume Maturation" },
  { id: "pta-b34-050", stem: "A PTA is treating a patient who takes insulin glargine (Lantus) for type 1 diabetes. The patient's blood glucose reading before the therapy session is 68 mg/dL. The PTA should:", options: ["Proceed with the planned vigorous exercise session to help lower blood glucose further", "Recognize this as mild hypoglycemia (below 70 mg/dL), provide the patient with 15-20 grams of fast-acting carbohydrate (juice, glucose tablets), wait 15 minutes, recheck blood glucose, and only proceed with exercise once glucose is above 100 mg/dL", "Instruct the patient to take an additional dose of insulin before exercising", "Document the reading and proceed with treatment without intervention"], correctIndex: 1, rationale: "A blood glucose of 68 mg/dL is below the hypoglycemic threshold (70 mg/dL). Exercise further lowers blood glucose through increased muscular glucose uptake, making vigorous exercise dangerous in a hypoglycemic state (risking seizures, loss of consciousness, cardiovascular events). The 15-15 rule: provide 15-20 grams of fast-acting carbohydrate, wait 15 minutes, recheck. Exercise should not begin until glucose is above 100 mg/dL to provide a safety margin. Additional insulin would further drop glucose. Proceeding without intervention risks a severe hypoglycemic event during exercise. The PTA must be able to recognize and manage hypoglycemia in diabetic patients.", difficulty: 1, category: "Pharmacology for PTAs", topic: "Pre-Exercise Hypoglycemia Management" },
  { id: "pta-b34-051", stem: "A PTA is analyzing the biomechanics of a patient performing a step-up exercise. As the patient places the right foot on a 12-inch step and begins to ascend, the primary concentric muscle action occurring at the right knee is:", options: ["Hamstring concentric contraction producing knee flexion", "Quadriceps concentric contraction producing knee extension to lift the body against gravity onto the step", "Gastrocnemius eccentric contraction", "Gluteus maximus concentric contraction only"], correctIndex: 1, rationale: "During a step-up, the ascending limb (right leg on the step) performs a closed-kinetic-chain movement against gravity. The quadriceps contract concentrically to extend the knee, lifting the body's center of mass upward onto the step. The hamstrings do not concentrically flex the knee during ascent; that would lower the body. The gastrocnemius assists with ankle plantarflexion during push-off but the primary knee action is quadriceps extension. While the gluteus maximus contributes with hip extension, the question asks specifically about the knee joint action. Understanding concentric versus eccentric muscle actions during functional tasks is essential for exercise prescription.", difficulty: 1, category: "Biomechanics & Kinesiology", topic: "Step-Up Concentric Knee Action" },
  { id: "pta-b34-052", stem: "A PTA is interpreting a forest plot from a meta-analysis on the effectiveness of TENS for chronic musculoskeletal pain. The summary diamond (overall effect estimate) crosses the line of no effect (zero). This means:", options: ["TENS is strongly effective for chronic musculoskeletal pain", "The overall pooled result does not demonstrate a statistically significant difference between TENS and control, as the confidence interval includes the null value (no effect)", "The meta-analysis has too few studies to draw conclusions", "All individual studies showed no benefit from TENS"], correctIndex: 1, rationale: "In a forest plot, the line of no effect (typically zero for mean differences or one for risk ratios) represents no difference between groups. When the summary diamond (pooled effect estimate with its confidence interval) crosses this line, it means the confidence interval includes the possibility of no effect, and the overall result is not statistically significant. This does not necessarily mean the treatment has no effect; it means the evidence does not confidently exclude no effect. Individual studies may show varying results. The number of studies is represented by the individual lines, not the diamond position. Some individual studies may show benefit even when the pooled result is non-significant.", difficulty: 3, category: "Evidence-Based Practice", topic: "Forest Plot Interpretation" },
  { id: "pta-b34-053", stem: "A PTA is treating a patient with chronic pain who has been referred for a multidisciplinary pain program. The patient asks why they need to see a psychologist when their pain is 'real and physical.' The PTA should explain that:", options: ["The referral to a psychologist means the medical team believes the pain is imaginary", "Pain is a complex experience involving sensory, emotional, and cognitive components; psychological interventions address the emotional and cognitive factors (anxiety, depression, catastrophizing, coping strategies) that modulate the pain experience, and this does not mean the pain is not real", "Only patients with mental illness need psychological pain management", "The PTA agrees that psychology has no role in pain management"], correctIndex: 1, rationale: "The biopsychosocial model of pain recognizes that pain is a multidimensional experience influenced by biological (tissue factors, nervous system sensitization), psychological (thoughts, emotions, beliefs, coping strategies), and social (work, relationships, cultural factors) components. Psychological interventions (CBT, ACT, mindfulness) address the cognitive-emotional dimensions that significantly modulate pain perception and disability. This does not invalidate the physical reality of pain. Stating the pain is imaginary is incorrect and harmful. Psychological pain management benefits all chronic pain patients, not only those with mental illness. Dismissing psychology contradicts the evidence base for multidisciplinary pain management.", difficulty: 1, category: "Pain Management", topic: "Biopsychosocial Pain Education" },
  { id: "pta-b34-054", stem: "A PTA is working in an outpatient orthopedic clinic and discovers during treatment that a patient's plan of care expired 3 days ago without being renewed by the supervising PT. The patient is midway through a session of therapeutic exercises. The PTA should:", options: ["Complete the current session and continue treating the patient on the expired plan without notifying anyone", "Complete the current treatment session for patient safety, document the situation, and immediately notify the supervising PT that the plan of care requires re-evaluation and renewal before the next scheduled visit", "Abruptly stop the treatment session and send the patient home immediately", "Write a new plan of care independently to keep the patient on schedule"], correctIndex: 1, rationale: "An expired plan of care means the PTA is technically treating without a valid authorization. The safest approach is to complete the current session (abruptly stopping mid-treatment could compromise patient safety) while immediately notifying the supervising PT of the expired plan. The PT must re-evaluate and establish a new plan of care before the next visit. Continuing to treat on an expired plan violates practice standards and potentially regulations. The PTA cannot write a plan of care; this is exclusively within the PT's scope. Abruptly stopping mid-treatment is not in the patient's best interest for the current session.", difficulty: 2, category: "Clinical Prioritization & Workflow", topic: "Expired Plan of Care Management" },
  { id: "pta-b34-055", stem: "A PTA is monitoring a patient performing pursed-lip breathing during ambulation. The patient has severe COPD with emphysema. The primary physiological benefit of pursed-lip breathing for this patient is:", options: ["Increasing the respiratory rate to improve minute ventilation", "Creating a small amount of positive back-pressure during exhalation that stents the airways open, preventing premature airway collapse and air trapping, thereby improving gas exchange and reducing dyspnea", "Strengthening the diaphragm through increased resistance", "Increasing oxygen delivery by concentrating inhaled air"], correctIndex: 1, rationale: "In emphysema, the airways lose elastic recoil and tend to collapse during exhalation, trapping air in the alveoli (air trapping/dynamic hyperinflation). Pursed-lip breathing creates a small amount of positive pressure (approximately 5 cmH2O) during exhalation that acts as a pneumatic splint, keeping airways open longer during exhalation. This reduces air trapping, improves CO2 elimination, allows more complete exhalation, and reduces the work of breathing and dyspnea. Pursed-lip breathing slows (not increases) respiratory rate. The resistance is in the exhalation, not designed for diaphragm strengthening. It does not concentrate inhaled air.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "Pursed-Lip Breathing Physiology" },
  { id: "pta-b34-056", stem: "A PTA is treating a patient with a chronic wound on the lateral malleolus. The wound has failed to progress over 8 weeks despite appropriate moist wound management. The PTA notes the wound bed is pale pink with minimal granulation. The patient's hemoglobin is 8.2 g/dL (normal 12-16 g/dL for females). This laboratory value suggests:", options: ["Normal hemoglobin levels with no impact on wound healing", "The patient has anemia, which reduces oxygen-carrying capacity to the wound bed, impairing fibroblast function, collagen synthesis, and bacterial killing by white blood cells, contributing to the wound healing failure", "The hemoglobin is elevated and causing excessive bleeding in the wound", "Hemoglobin levels have no relationship to wound healing"], correctIndex: 1, rationale: "Hemoglobin of 8.2 g/dL represents significant anemia (normal female range 12-16 g/dL). Hemoglobin carries oxygen, and adequate tissue oxygenation is critical for wound healing: fibroblasts require oxygen for collagen synthesis, neutrophils need oxygen for the oxidative burst that kills bacteria, and angiogenesis (new blood vessel formation) requires adequate oxygen tension. The pale wound bed with minimal granulation is consistent with inadequate tissue oxygenation from anemia. The hemoglobin is below normal, not elevated. Hemoglobin is one of the most important laboratory values for wound healing assessment. The PTA should communicate this finding to the healthcare team.", difficulty: 3, category: "Integumentary & Wound Care", topic: "Anemia Impact on Wound Healing" },
  { id: "pta-b34-057", stem: "A PTA is educating a patient with a new transtibial prosthesis about sock management. The patient asks why they need to add socks throughout the day. The PTA should explain that:", options: ["Additional socks are only for warmth and comfort", "The residual limb volume fluctuates throughout the day (typically decreasing), and adding prosthetic socks compensates for volume loss to maintain proper socket fit, prevent pistoning (excessive vertical movement), and avoid skin breakdown from friction", "Socks should never be changed during the day once the prosthesis is donned", "Only one thickness of sock should ever be used"], correctIndex: 1, rationale: "Residual limb volume changes throughout the day due to fluid shifts, activity level, and gravitational effects. Volume typically decreases during weight-bearing activity as fluid is redistributed. As the limb shrinks, the socket becomes loose, causing pistoning (the limb slides up and down within the socket), which creates friction, skin irritation, and potentially tissue breakdown. Adding prosthetic socks (measured in ply) fills the space created by volume loss, maintaining intimate socket fit. Socks serve a critical biomechanical function beyond warmth. Sock management throughout the day is essential for proper prosthetic use. Different thicknesses may be needed at different times.", difficulty: 1, category: "Prosthetics & Orthotics", topic: "Prosthetic Sock Volume Management" },
  { id: "pta-b34-058", stem: "A PTA is treating a patient who reports taking over-the-counter naproxen (Aleve) daily for the past 6 months for chronic shoulder pain. The patient mentions increased heartburn and dark-colored stools. The PTA should:", options: ["Recommend the patient increase the naproxen dose for better pain control", "Recognize that chronic NSAID use can cause gastrointestinal complications including peptic ulcers and GI bleeding (dark stools suggest upper GI bleeding), communicate this concern urgently to the supervising PT, and advise the patient to contact their physician immediately", "Advise the patient to take the naproxen on an empty stomach for faster absorption", "Dismiss the GI symptoms as unrelated to the naproxen use"], correctIndex: 1, rationale: "Chronic NSAID (naproxen, ibuprofen) use inhibits cyclooxygenase (COX) enzymes, reducing protective prostaglandins in the gastric mucosa. This increases the risk of peptic ulcers and GI bleeding. Dark stools (melena) suggest upper GI bleeding, which is a serious complication requiring urgent medical evaluation. The PTA should recognize this medication-symptom relationship and facilitate urgent medical follow-up. Increasing the dose would worsen GI risk. NSAIDs should be taken with food to reduce GI irritation, not on an empty stomach. The temporal relationship between chronic NSAID use and GI symptoms strongly suggests a causal connection.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Chronic NSAID GI Complications" },
  { id: "pta-b34-059", stem: "A PTA is analyzing the closed-kinetic-chain mechanics of the ankle during the mid-stance phase of gait. As the tibia advances over the fixed foot, the motion occurring at the talocrural joint is:", options: ["Plantarflexion as the heel lifts off the ground", "Dorsiflexion, as the tibia moves anteriorly over the fixed talus, controlled eccentrically by the gastrocnemius-soleus complex which decelerates forward tibial progression", "Inversion of the subtalar joint only", "No motion occurs at the talocrural joint during mid-stance"], correctIndex: 1, rationale: "During mid-stance in a closed kinetic chain, the foot is fixed on the ground and the tibia advances forward over the talus. This tibial advancement represents talocrural dorsiflexion (the angle between the tibia and foot decreases). The gastrocnemius-soleus complex contracts eccentrically to control the rate of tibial advancement, preventing the tibia from moving too rapidly forward (which would cause the knee to flex excessively). Plantarflexion occurs later during pre-swing/push-off. The question asks about the talocrural joint, not the subtalar joint. Significant motion occurs at the talocrural joint during mid-stance; it is one of the critical phases for ankle dorsiflexion range.", difficulty: 3, category: "Biomechanics & Kinesiology", topic: "Closed-Chain Ankle Mid-Stance" },
  { id: "pta-b34-060", stem: "A PTA is treating a patient with peripheral arterial disease (PAD) using a supervised walking program. The patient develops claudication pain in the calves at 3 minutes of walking. According to evidence-based claudication exercise protocols, the PTA should instruct the patient to:", options: ["Stop walking immediately and not attempt walking again that session", "Continue walking until near-maximal claudication pain (3-4 on a 5-point claudication scale), then rest until the pain subsides completely, and resume walking, repeating this cycle for a total of 30-60 minutes per session", "Push through the pain and walk continuously for 60 minutes without stopping", "Substitute cycling for walking since walking causes pain"], correctIndex: 1, rationale: "Evidence-based claudication exercise protocols recommend walking to moderate-to-near-maximal claudication pain, resting until pain resolves, then resuming walking. This intermittent walking approach for 30-60 minutes per session, 3-5 times per week, promotes collateral blood vessel development and improves walking tolerance. Walking to complete pain onset and stopping for the session provides insufficient stimulus. Continuous walking through maximal pain is not recommended and could be harmful. Walking is the specific exercise mode with the strongest evidence for PAD; cycling provides less benefit for claudication because it does not replicate the specific demands that stimulate collateral circulation in the lower leg.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "PAD Claudication Exercise Protocol" },
  { id: "pta-b34-061", stem: "A PTA is performing sharp debridement on a wound as permitted within their state practice act and under the supervision of the PT. The patient is taking clopidogrel (Plavix) for coronary stent placement. The PTA should be aware that:", options: ["Clopidogrel has no effect on wound debridement", "Clopidogrel is an antiplatelet medication that inhibits platelet aggregation, increasing bleeding risk during sharp debridement; the PTA should have hemostatic agents readily available and apply sustained direct pressure to any bleeding points", "Clopidogrel accelerates wound healing and makes debridement unnecessary", "The patient should stop taking clopidogrel 24 hours before debridement without consulting their physician"], correctIndex: 1, rationale: "Clopidogrel (Plavix) irreversibly inhibits platelet aggregation by blocking the P2Y12 ADP receptor, increasing bleeding risk during any procedure involving tissue disruption including sharp debridement. The PTA should prepare hemostatic agents (silver nitrate sticks, alginate dressings, hemostatic powder) and be ready to apply sustained direct pressure. The medication significantly affects procedural bleeding risk. Clopidogrel does not promote wound healing or eliminate the need for debridement. Patients should never be advised to stop antiplatelet medications without physician guidance, as abrupt discontinuation can cause stent thrombosis (a life-threatening emergency).", difficulty: 3, category: "Integumentary & Wound Care", topic: "Antiplatelet Debridement Precautions" },
  { id: "pta-b34-062", stem: "A PTA is treating a patient with bilateral transtibial amputations who is learning to use bilateral prostheses. During parallel bar gait training, the patient demonstrates excessive lordosis of the lumbar spine. This postural deviation during prosthetic gait is MOST likely caused by:", options: ["Bilateral hip flexion contractures that prevent full hip extension during stance, causing the patient to compensate by increasing lumbar lordosis to achieve an upright trunk position", "Prosthetic feet with excessive dorsiflexion", "Sockets that are too tight", "Excessive knee flexion during stance"], correctIndex: 0, rationale: "Hip flexion contractures are common after transtibial amputation due to prolonged sitting and knee flexion positioning. When bilateral hip flexion contractures prevent full hip extension during stance, the patient compensates by anteriorly tilting the pelvis and increasing lumbar lordosis to bring the trunk upright over the base of support. This is especially pronounced with bilateral amputations. Excessive foot dorsiflexion would shift weight posteriorly. Tight sockets can cause various issues but not specifically increased lordosis. Excessive knee flexion would cause a crouched gait, not increased lordosis. Addressing hip flexion contractures through stretching is essential for correcting this gait deviation.", difficulty: 3, category: "Prosthetics & Orthotics", topic: "Bilateral Prosthetic Lordosis" },
  { id: "pta-b34-063", stem: "A PTA is treating a patient who takes levothyroxine (Synthroid) for hypothyroidism. The patient presents with excessive fatigue, cold intolerance, weight gain, and bradycardia. These symptoms suggest:", options: ["Levothyroxine toxicity requiring dose reduction", "The patient's hypothyroidism may be inadequately controlled (sub-therapeutic levothyroxine dose), and the PTA should communicate these symptoms to the supervising PT for referral to the prescribing provider for thyroid function testing", "Normal expected effects of levothyroxine therapy", "An allergic reaction to levothyroxine requiring immediate discontinuation"], correctIndex: 1, rationale: "The symptoms described (fatigue, cold intolerance, weight gain, bradycardia) are classic manifestations of hypothyroidism, suggesting the levothyroxine replacement dose may be insufficient to maintain euthyroid status. Levothyroxine toxicity (hyperthyroid symptoms) would present with tachycardia, heat intolerance, weight loss, anxiety, and tremor; the opposite of this presentation. These are not normal effects of proper levothyroxine therapy; the goal is to eliminate hypothyroid symptoms. Allergic reactions to levothyroxine are rare and present with rash, urticaria, or anaphylaxis, not hypothyroid symptoms. The PTA should communicate the findings for medical follow-up.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Subtherapeutic Levothyroxine Recognition" },
  { id: "pta-b34-064", stem: "A PTA is explaining the biomechanical advantage of using a cane in the hand contralateral to an affected hip. By placing the cane in the opposite hand, the lever arm mechanics:", options: ["Have no effect on hip joint forces; cane side is purely for patient preference", "Reduce the demand on the ipsilateral hip abductors by creating a counterbalancing moment on the contralateral side, significantly reducing the compressive forces on the affected hip joint compared to using the cane on the same side", "Increase the forces on the affected hip by shifting the center of gravity further away", "Only affect the shoulder joint, not the hip"], correctIndex: 1, rationale: "Using a cane contralaterally creates a counterbalancing torque: the cane applies force on the opposite side of the body from the affected hip, creating an external abduction moment that assists the hip abductors. This reduces the muscular force required from the gluteus medius on the affected side. Since hip joint compressive force is the sum of body weight and abductor muscle force, reducing abductor demand significantly reduces total hip joint compression (studies show up to 40-60% reduction). Using the cane ipsilaterally provides balance support but does not create the beneficial lever arm to reduce abductor demand. The biomechanical effect directly impacts the hip joint, not just the shoulder.", difficulty: 2, category: "Biomechanics & Kinesiology", topic: "Contralateral Cane Hip Biomechanics" },
  { id: "pta-b34-065", stem: "A PTA is reviewing a cohort study that followed patients with rotator cuff tears for 5 years. The study reports a relative risk (RR) of 2.5 for developing shoulder arthritis in patients with full-thickness tears compared to those with partial tears. The PTA should interpret this as:", options: ["Patients with full-thickness tears are 25% more likely to develop arthritis", "Patients with full-thickness tears are 2.5 times more likely to develop shoulder arthritis compared to those with partial tears over the 5-year follow-up period", "The absolute risk of arthritis is 2.5%", "Full-thickness tears cause arthritis in all patients within 2.5 years"], correctIndex: 1, rationale: "Relative risk (RR) compares the probability of an outcome in the exposed group to the unexposed group. An RR of 2.5 means patients with full-thickness tears are 2.5 times (or 150% more) likely to develop arthritis compared to those with partial tears. This is different from a 25% increase (which would be an RR of 1.25). RR does not provide absolute risk information (the actual percentage of patients affected). Cohort studies show associations over time but an RR of 2.5 does not mean all patients develop the condition. Understanding relative risk helps clinicians communicate prognosis and informs shared decision-making.", difficulty: 2, category: "Evidence-Based Practice", topic: "Relative Risk Interpretation" },
  { id: "pta-b34-066", stem: "A PTA is treating a patient with chronic widespread pain who demonstrates significant fear of movement and states that pain always means damage. After explaining the neuroplasticity of pain, the PTA implements therapeutic neuroscience education (TNE). A key concept to convey is:", options: ["Pain always directly corresponds to tissue damage in a 1:1 relationship", "In chronic pain, the nervous system can become sensitized and amplify pain signals, meaning pain intensity no longer accurately reflects the degree of tissue damage; understanding this can reduce the threat value of pain and improve function", "The patient should ignore all pain signals because they are meaningless in chronic pain", "Pain education should replace all physical interventions in chronic pain management"], correctIndex: 1, rationale: "Therapeutic neuroscience education teaches patients that chronic pain involves nervous system sensitization where the 'alarm system' becomes overprotective. Pain can persist and amplify even after tissues have healed due to neuroplastic changes in the peripheral and central nervous system. Understanding this reduces the perceived threat of pain and movement, decreasing fear-avoidance behavior. Pain in chronic conditions does not have a 1:1 relationship with tissue damage. Pain signals should not be completely ignored; patients should learn to interpret pain as information rather than a threat. TNE complements (does not replace) physical interventions; the combination is more effective than either alone.", difficulty: 2, category: "Pain Management", topic: "Therapeutic Neuroscience Education" },
  { id: "pta-b34-067", stem: "A PTA is working in an acute care hospital and receives orders for physical therapy on two patients simultaneously. Patient A is a 45-year-old post-motor vehicle accident with multiple fractures, stable vitals, and physician clearance for mobilization. Patient B is a 78-year-old with pneumonia whose nurse reports oxygen saturation just dropped to 84% on room air. The PTA should:", options: ["See Patient A first since they have the more complex orthopedic presentation", "Immediately respond to Patient B's situation by notifying the nurse that Patient B requires acute medical attention for the desaturation before physical therapy can be initiated, then proceed to assess and treat Patient A", "Treat both patients simultaneously to be efficient", "Wait until both patients are fully stable before initiating any treatment"], correctIndex: 1, rationale: "Patient B's SpO2 of 84% on room air represents acute hypoxemia requiring immediate medical intervention (supplemental oxygen, respiratory assessment) before physical therapy is appropriate. The PTA should ensure the nursing staff is actively managing the desaturation. Initiating PT during acute desaturation is unsafe and could worsen the patient's respiratory status. Patient A is stable and cleared for mobilization, making them the appropriate first therapy visit. Treating two patients simultaneously compromises safety and quality. Waiting for both to be fully stable delays beneficial intervention for Patient A who is currently appropriate for treatment.", difficulty: 2, category: "Clinical Prioritization & Workflow", topic: "Acute Desaturation Patient Triage" },
  { id: "pta-b34-068", stem: "A PTA is monitoring a patient performing diaphragmatic breathing exercises. The patient places one hand on the chest and one on the abdomen. During correct diaphragmatic breathing, the PTA should observe:", options: ["Both hands rising equally during inspiration", "The abdominal hand rising during inspiration (indicating diaphragmatic descent and abdominal expansion) while the chest hand remains relatively still, followed by the abdominal hand falling during expiration", "The chest hand rising while the abdominal hand falls during inspiration", "No movement of either hand during breathing"], correctIndex: 1, rationale: "Diaphragmatic breathing emphasizes diaphragm contraction during inspiration: as the diaphragm descends, it displaces abdominal contents downward and outward, causing the abdomen to expand (abdominal hand rises). The chest should remain relatively quiet, indicating minimal accessory muscle use and upper chest expansion. During expiration, the diaphragm relaxes and ascends, and the abdomen falls. Both hands rising equally suggests combined chest and abdominal breathing. Chest rising while abdomen falls indicates paradoxical breathing (diaphragm dysfunction). No movement indicates apnea. This breathing pattern improves ventilation efficiency, reduces work of breathing, and is especially beneficial for COPD patients.", difficulty: 1, category: "Cardiopulmonary Physical Therapy", topic: "Diaphragmatic Breathing Assessment" },
  { id: "pta-b34-069", stem: "A PTA is evaluating a skin graft donor site on a patient's thigh. The site was harvested 10 days ago and is covered with a transparent film dressing. The PTA observes that the area beneath the dressing appears moist with a thin layer of serous fluid, and the tissue is a healthy pink color. The PTA should:", options: ["Remove the dressing and apply dry gauze to the donor site", "Leave the dressing intact as this represents normal healing of a split-thickness skin graft donor site; the moist environment under the transparent film promotes epithelialization", "Request that the surgeon re-graft the donor site", "Apply topical antibiotic ointment over the transparent film dressing"], correctIndex: 1, rationale: "Split-thickness skin graft donor sites heal by re-epithelialization from the remaining epidermal appendages (hair follicles, sweat glands) in the residual dermis. A moist wound environment under a transparent film dressing optimizes re-epithelialization by allowing epithelial cells to migrate across the wound surface without desiccation. Serous fluid and healthy pink tissue are normal findings at 10 days. Removing the dressing and applying dry gauze would create a dry environment that slows healing and increases pain. Re-grafting is unnecessary for a normally healing donor site. Antibiotic ointment applied over the intact film cannot penetrate to the wound surface.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Skin Graft Donor Site Healing" },
  { id: "pta-b34-070", stem: "A PTA is assessing a patient with a dynamic AFO (posterior leaf spring design) for foot drop. The patient reports that the AFO does not provide enough dorsiflexion assistance during swing phase. The PTA checks the AFO and notes the posterior strut appears overly flexible. The MOST appropriate action is:", options: ["Add rigid ankle strapping to compensate for the flexible strut", "Document the finding and communicate with the orthotist that the posterior leaf spring may need to be made with a stiffer material or thicker trim lines to provide adequate dorsiflexion assistance during swing phase", "Switch the patient to a rigid AFO without consulting the orthotist or PT", "Instruct the patient to walk faster to overcome the dorsiflexion deficit"], correctIndex: 1, rationale: "A posterior leaf spring AFO relies on the elastic energy stored in the posterior strut during stance (as it bends under dorsiflexion forces) to spring the foot back into dorsiflexion during swing phase. If the strut is too flexible, it does not store enough energy to adequately assist dorsiflexion. The orthotist can modify the device by using stiffer thermoplastic material or widening the trim lines (increasing material width) to increase rigidity. Adding rigid strapping changes the design intent. The PTA cannot independently change the orthotic type. Walking faster does not address the biomechanical deficit and may increase fall risk from inadequate foot clearance.", difficulty: 2, category: "Prosthetics & Orthotics", topic: "Posterior Leaf Spring AFO Stiffness" },
  { id: "pta-b34-071", stem: "A PTA is treating a patient who takes albuterol (rescue inhaler) and fluticasone/salmeterol (Advair, maintenance inhaler) for asthma. Before beginning an exercise session, the patient asks which inhaler to use prophylactically. The PTA should advise:", options: ["The fluticasone/salmeterol (maintenance inhaler) 15 minutes before exercise", "The albuterol (rescue inhaler) 15-20 minutes before exercise to prevent exercise-induced bronchospasm, as short-acting beta-2 agonists provide rapid bronchodilation for 4-6 hours", "Both inhalers simultaneously immediately before exercise", "Neither inhaler; medication is not needed before exercise for asthma patients"], correctIndex: 1, rationale: "Albuterol is a short-acting beta-2 agonist (SABA) that provides rapid bronchodilation within 5-15 minutes and is the recommended prophylactic treatment for exercise-induced bronchospasm. Using it 15-20 minutes before exercise provides a protective window of 4-6 hours. Fluticasone/salmeterol is a maintenance combination (inhaled corticosteroid + long-acting beta-2 agonist) taken on a regular schedule, not as a pre-exercise rescue medication. Using both simultaneously before exercise is not indicated. Exercise-induced bronchospasm is common in asthma patients, and prophylactic SABA use before exercise is a standard evidence-based recommendation.", difficulty: 1, category: "Pharmacology for PTAs", topic: "Pre-Exercise Asthma Inhaler" },
  { id: "pta-b34-072", stem: "A PTA is analyzing a patient's gait and measures a cadence of 80 steps/minute with a stride length of 1.0 meter. The patient's calculated gait velocity is:", options: ["80 meters per minute", "40 meters per minute, calculated by multiplying cadence (80 steps/min) by stride length (1.0 m) and dividing by 2 (since one stride equals two steps), resulting in a velocity of approximately 0.67 m/s", "160 meters per minute", "Cannot be calculated with this information"], correctIndex: 1, rationale: "Gait velocity = (cadence x stride length) / 2, because cadence is measured in steps per minute but stride length covers two steps. Therefore: (80 steps/min x 1.0 m/stride) / 2 = 40 m/min, or approximately 0.67 m/s. Alternatively, velocity = step length x cadence, where step length is half the stride length (0.5 m): 0.5 m x 80 steps/min = 40 m/min. The calculation of 80 m/min would incorrectly treat each step as a full stride. The value of 160 m/min doubles rather than halves the product. The information provided is sufficient for the calculation. Normal adult gait velocity is approximately 1.2-1.4 m/s, indicating this patient walks significantly slower than normal.", difficulty: 2, category: "Biomechanics & Kinesiology", topic: "Gait Velocity Calculation" },
  { id: "pta-b34-073", stem: "A PTA is using the Pressure Ulcer Scale for Healing (PUSH) tool to track wound healing progress. The PUSH tool measures three wound characteristics that are scored and summed. These three parameters are:", options: ["Wound location, patient age, and wound duration", "Surface area (length x width), exudate amount, and tissue type in the wound bed", "Wound temperature, wound pH, and bacterial count", "Depth, tunneling length, and undermining circumference"], correctIndex: 1, rationale: "The PUSH tool (developed by the NPUAP) uses three parameters to generate a composite score tracking healing over time: surface area (length x width, scored 0-10), exudate amount (none, light, moderate, heavy, scored 0-3), and tissue type (closed, epithelial, granulation, slough, necrotic, scored 0-4). Total PUSH scores range from 0 (healed) to 17 (worst). Decreasing scores over time indicate healing progression. The tool does not include wound location, patient age, duration, temperature, pH, bacterial count, depth, tunneling, or undermining. The PUSH tool is valued for its simplicity and reliability in tracking healing trends across serial assessments.", difficulty: 2, category: "Integumentary & Wound Care", topic: "PUSH Wound Assessment Tool" },
  { id: "pta-b34-074", stem: "A PTA is working with a patient who has a C7 complete spinal cord injury. The patient is being fitted for a wheelchair and the PT has ordered a lightweight rigid-frame manual wheelchair. For optimal propulsion efficiency and shoulder preservation, the rear axle should be positioned:", options: ["As far posterior as possible for maximum stability", "Directly below or slightly anterior to the shoulder joint when the patient is seated, placing the hand at the top-dead-center of the push rim with the elbow flexed approximately 100-120 degrees, which minimizes shoulder joint stress and maximizes propulsion efficiency", "At the level of the patient's knees", "In a fixed position that cannot be adjusted"], correctIndex: 1, rationale: "Rear axle position significantly affects propulsion biomechanics and shoulder health. Positioning the axle below or slightly anterior to the shoulder places the hand optimally on the push rim, allowing a longer, more efficient push stroke with less shoulder impingement. The 100-120 degree elbow flexion angle provides optimal muscle length-tension relationships for propulsion. An axle too far posterior increases rolling resistance, reduces push arc, and increases shoulder stress. The axle should be at shoulder level, not knee level. Modern ultralight wheelchairs have adjustable axle positions specifically to optimize individual propulsion mechanics. Proper axle positioning reduces the risk of shoulder overuse injuries, which affect up to 70% of long-term manual wheelchair users.", difficulty: 3, category: "Clinical Prioritization & Workflow", topic: "Wheelchair Axle Positioning" },
  { id: "pta-b34-075", stem: "A PTA is performing phase II outpatient cardiac rehabilitation with a patient who had a myocardial infarction 6 weeks ago. The patient's target heart rate has been prescribed at 60-80% of heart rate reserve using the Karvonen formula. The patient's resting heart rate is 70 bpm and maximum heart rate from a recent graded exercise test was 160 bpm. The target heart rate range is:", options: ["96-112 bpm", "124-142 bpm, calculated as: HRR = 160-70 = 90; lower target = 70 + (0.60 x 90) = 124 bpm; upper target = 70 + (0.80 x 90) = 142 bpm", "42-56 bpm", "160-180 bpm"], correctIndex: 1, rationale: "The Karvonen formula uses heart rate reserve (HRR): HRR = HRmax - HRrest = 160 - 70 = 90 bpm. Target HR = HRrest + (intensity x HRR). Lower limit: 70 + (0.60 x 90) = 70 + 54 = 124 bpm. Upper limit: 70 + (0.80 x 90) = 70 + 72 = 142 bpm. The range 96-112 would result from using straight percentages of max HR without accounting for resting HR (160 x 0.60 = 96). The Karvonen formula is preferred because it accounts for resting heart rate, making it more individualized. Values of 42-56 are below resting heart rate and physiologically impossible during exercise. Values of 160-180 exceed the measured maximum heart rate.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "Karvonen Formula Calculation" },
  { id: "pta-b34-076", stem: "A PTA is treating a patient with a neuropathic ulcer on the plantar surface of the foot secondary to diabetic peripheral neuropathy. The patient has been provided with a total contact cast (TCC) for offloading. The primary mechanism by which the TCC promotes healing is:", options: ["By increasing blood flow through compression of the foot", "By redistributing plantar pressure across the entire plantar surface of the foot rather than concentrating it on the ulcer site, effectively reducing focal pressure by up to 60-80% and preventing repetitive trauma during ambulation", "By keeping the wound completely dry and preventing any moisture", "By immobilizing the ankle joint to prevent all foot motion"], correctIndex: 1, rationale: "Total contact casting is the gold standard for offloading diabetic plantar ulcers. The TCC works by conforming intimately to the foot's contours, distributing weight-bearing forces across the entire plantar surface rather than concentrating pressure at the ulcer site. This reduces focal plantar pressures by 60-80% and eliminates the repetitive trauma that perpetuates the ulcer. The TCC does not primarily work through compression or blood flow enhancement. While the cast does maintain a moist wound environment, its primary mechanism is pressure redistribution. The TCC allows some ankle motion for ambulation; complete immobilization is not its primary purpose. The forced compliance aspect (the patient cannot remove it) also contributes to effectiveness.", difficulty: 3, category: "Integumentary & Wound Care", topic: "Total Contact Cast Mechanism" },
  { id: "pta-b34-077", stem: "A PTA is treating a patient who reports that their physician prescribed tramadol for moderate pain following a knee arthroscopy. The patient also takes sertraline (an SSRI antidepressant). The PTA should be aware that:", options: ["This medication combination has no clinical significance", "Tramadol combined with SSRIs increases the risk of serotonin syndrome, a potentially life-threatening condition characterized by agitation, hyperthermia, tachycardia, muscle rigidity, and clonus; the PTA should monitor for these symptoms and report any concerns immediately", "Tramadol is a pure NSAID with no central nervous system effects", "Sertraline counteracts all analgesic effects of tramadol"], correctIndex: 1, rationale: "Tramadol has dual mechanisms: weak opioid agonist activity AND inhibition of serotonin and norepinephrine reuptake. When combined with SSRIs (sertraline, fluoxetine, paroxetine) which also increase serotonin, there is an increased risk of serotonin syndrome. Symptoms include agitation, confusion, hyperthermia, tachycardia, hypertension, muscle rigidity, clonus (involuntary rhythmic contractions), and in severe cases, seizures and death. This combination is clinically significant and the PTA should be vigilant. Tramadol is not a pure NSAID; it has both opioid and serotonergic properties. Sertraline does not counteract tramadol's effects but rather creates a potentially dangerous synergistic serotonergic effect.", difficulty: 3, category: "Pharmacology for PTAs", topic: "Tramadol SSRI Serotonin Syndrome" },
  { id: "pta-b34-078", stem: "A PTA is calculating the mechanical advantage of the biceps brachii during elbow flexion. The biceps inserts approximately 3 cm from the elbow joint axis, and the patient is holding a weight at 30 cm from the joint axis. The mechanical advantage of this lever system is:", options: ["10:1, giving the biceps a significant mechanical advantage", "0.1:1 (or 1:10), indicating a mechanical disadvantage where the biceps must generate approximately 10 times the force of the external load to maintain static equilibrium, but gaining a speed and range advantage", "1:1, indicating equal force requirements", "3:1, favoring the muscle force"], correctIndex: 1, rationale: "Mechanical advantage = effort arm / resistance arm = 3 cm / 30 cm = 0.1 (or 1:10 ratio). This means the biceps has a significant mechanical disadvantage: it must produce approximately 10 times the external load force to maintain equilibrium. Most skeletal muscles in the body operate at mechanical disadvantage (effort arm shorter than resistance arm). However, this arrangement provides a speed and range of motion advantage: a small muscle shortening produces a large displacement at the hand. A 10:1 ratio would mean the muscle needs only 1/10th the load force, which is incorrect. A 1:1 ratio would require equal arms. The 3:1 ratio reverses the correct calculation.", difficulty: 2, category: "Biomechanics & Kinesiology", topic: "Biceps Mechanical Advantage Lever" },
  { id: "pta-b34-079", stem: "A PTA is treating a patient with central post-stroke pain (thalamic pain syndrome) who reports constant burning pain in the hemiplegic upper extremity. Traditional analgesics have been ineffective. The PTA should understand that this type of pain:", options: ["Is best treated with local ice application to the affected extremity", "Is a central neuropathic pain condition caused by damage to the thalamic pain processing pathways in the brain, requiring multimodal management including medications targeting central pain mechanisms (anticonvulsants, antidepressants), desensitization techniques, mirror therapy, and functional task training", "Is always a sign of shoulder subluxation requiring a sling", "Will resolve spontaneously within 2 weeks without intervention"], correctIndex: 1, rationale: "Central post-stroke pain (thalamic pain syndrome) results from damage to central somatosensory pathways (usually the ventroposterolateral nucleus of the thalamus), causing spontaneous burning, aching, or shooting pain in the affected body regions. It is neuropathic in origin and does not respond well to traditional analgesics (NSAIDs, opioids). Management requires medications targeting central pain mechanisms (gabapentin, pregabalin, amitriptyline) combined with rehabilitation strategies (desensitization, mirror therapy, functional engagement). Ice may worsen neuropathic pain in some patients. While shoulder subluxation can cause pain post-stroke, the burning quality and distribution suggest central origin. Central post-stroke pain typically persists chronically without treatment.", difficulty: 3, category: "Pain Management", topic: "Central Post-Stroke Thalamic Pain" },
  { id: "pta-b34-080", stem: "A PTA in a rehabilitation facility is supervising a physical therapy aide who is assisting with patient care. The aide asks if they can independently perform ultrasound treatment on a patient while the PTA treats another patient. The PTA should respond that:", options: ["The aide can perform ultrasound independently as long as they have been trained on the device", "Physical therapy aides cannot independently perform skilled interventions such as therapeutic ultrasound; aides may only perform designated unskilled tasks under the direct supervision of the PTA or PT, and the PTA must be present in the immediate treatment area to supervise aide activities", "The aide can perform any treatment that the PTA delegates", "The aide can perform ultrasound if the patient consents"], correctIndex: 1, rationale: "Physical therapy aides are non-licensed support personnel who can only perform delegated, unskilled tasks (transporting patients, preparing treatment areas, cleaning equipment) under direct supervision. Therapeutic ultrasound is a skilled intervention requiring clinical judgment about parameters, contraindications, and patient response. Aides cannot independently deliver skilled modalities regardless of training. The PTA must maintain direct supervision (physical presence in the immediate area) when aides perform any patient-related tasks. Patient consent does not override scope-of-practice limitations. The PTA is responsible for ensuring appropriate delegation that protects patient safety and complies with practice regulations.", difficulty: 1, category: "Clinical Prioritization & Workflow", topic: "Aide Supervision Scope Limits" }
];
